  "tests": [
    {
      "name": "valid_role_admin",
      "input": {
        "role": "ADMIN"
      },
      "output": true,
      "notes": "Valid role should return true."
    },
    {
      "name": "valid_role_member",
      "input": {
        "role": "MEMBER"
      },
      "output": true,
      "notes": "Valid role should return true."
    },
    {
      "name": "valid_role_guest",
      "input": {
        "role": "GUEST"
      },
      "output": true,
      "notes": "Valid role should return true."
    },
    {
      "name": "invalid_role_unknown",
      "input": {
        "role": "UNKNOWN"
      },
      "output": false,
      "notes": "Invalid role should return false."
    },
    {
      "name": "empty_role",
      "input": {
        "role": ""
      },
      "output": false,
      "notes": "Empty role should return false."
    },
    {
      "name": "null_role",
      "input": {
        "role": null
      },
      "output": false,
      "notes": "Null role should return false."
    },
    {
      "name": "role_with_special_characters",
      "input": {
        "role": "ADMIN@123"
      },
      "output": false,
      "notes": "Role with special characters should return false."
    },
    {
      "name": "valid_role_superadmin",
      "input": {
        "role": "SUPERADMIN"
      },
      "output": true,
      "notes": "Valid role should return true."
    }
  ],
  "assumptions": "Roles must match the PROJECT_MEMBER_ROLE constants exactly.",
  "notes": "Ensure that all roles are validated against the defined constants."
}
